<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Personal Expense Tracker</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 20px;
        }

        .expense-row {
            border-bottom: 1px solid #ddd;
            padding: 10px;
            margin-top: 5px;
        }

        .cat-total {
            font-weight: bold;
            color: #2c3e50;
        }

        .delete-btn {
            background-color: #f44336;
            border: none;
            color: white;
            padding: 8px 12px;
            cursor: pointer;
            display: inline-block;
        }

        .delete-btn:hover {
            background-color: #d32f2f;
        }

        .total {
            font-weight: bold;
            color: #3498db;
        }

        input[type="number"] {
            width: 50px;
        }

        select, input {
            margin-top: 5px;
        }

        .form-error {
            color: red;
            font-size: 0.9em;
        }
    </style>
</head>
<body>
    <h1>Personal Expense Tracker</h1>

    <!-- Entry Form -->
    <form id="expense-form" onsubmit="return validateForm()">
        <div class="form-group">
            <label for="amount">Amount ($):</label>
            <input type="number" id="amount" step="0.01" min="0" required>
        </div>

        <div class="form-group">
            <label for="category">Category:</label>
            <select id="category" onchange="validateCategory()">
                <option value="">Select...</option>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>

        <div class="form-group">
            <label for="date">Date:</label>
            <input type="date" id="date" required>
        </div>

        <div class="form-group">
            <label for="note">Note (optional):</label>
            <input type="text" id="note" placeholder="Optional description">
        </div>

        <button type="submit" class="add-expense-btn">Add Expense</button>
    </form>

    <!-- Expenses List -->
    <div id="expenses-container"></div>

    <!-- Summary Section -->
    <div id="summary-section">
        <h2>Total Expenses: $<span id="total-value">0.00</span></h2>

        <div class="cat-total" data-cat="groceries">
            Groceries: $<span id="groceries-value">$0.00</span>
        </div>

        <div class="cat-total" data-cat="transport">
            Transport: $<span id="transport-value">$0.00</span>
        </div>

        <div class="cat-total" data-cat="bills">
            Bills: $<span id="bills-value">$0.00</span>
        </div>

        <div class="cat-total" data-cat="fun">
            Fun: $<span id="fun-value">$0.00</span>
        </div>
    </div>

    <!-- Filters -->
    <div id="filters-container">
        <label>Filter by Category:</label>
        <select id="filter-category"></select>

        <label>Filters from and to date:</label>
        <input type="date" id="start-date" required>
        <input type="date" id="end-date" required>
    </div>

    <!-- Delete buttons for each expense -->
    <div class="delete-btn" data-expense-id="1">Delete Expense 1</div>
    <div class="delete-btn" data-expense-id="2">Delete Expense 2</div>
    <div class="delete-btn" data-expense-id="3">Delete Expense 3</div>

    <script>
        // State variables
        let expenses = [];
        const storedExpenses = localStorage.getItem('expenseTrackerExpenses');

        // Initialize from storage if available
        if (storedExpenses) {
            const expData = JSON.parse(storedExpenses);
            initializeExpenses(expData);
        }

        function initializeExpenses(data) {
            expenses = data;
            renderExpenses();
            updateSummary();
            updateFilters();
        }

        // Render all expenses
        function renderExpenses() {
            const container = document.getElementById('expenses-container');
            container.innerHTML = '';

            expenses.forEach(expense => {
                const row = document.createElement('div');
                row.className = 'expense-row';

                // Sort by date newest first (descending)
                if (expense.date) {
                    expense.sort((a, b) => new Date(b.date) - new Date(a.date));
                }

                row.innerHTML = `
                    <span class="cat-total" data-cat="${expense.category}">${expense.amount.toFixed(2)}</span>
                    <div class="delete-btn" data-expense-id="${expense.id}">Delete</div>
                    <small>${new Date(expense.date).toLocaleDateString()}</small>
                `;

                container.appendChild(row);
            });
        }

        // Update total expenses
        function updateTotal() {
            const total = expenses.reduce((sum, expense) => sum + expense.amount, 0);
            document.getElementById('total-value').textContent = total.toFixed(2);
        }

        // Update per-category totals
        function updateCategoryTotals() {
            const categories = ['groceries', 'transport', 'bills', 'fun'];
            categories.forEach(cat => {
                const catElement = document.querySelector(`[data-cat="${cat}"]`);
                if (catElement) {
                    const total = expenses.filter(expense => expense.category === cat).reduce((sum, e) => sum + e.amount, 0);
                    catElement.textContent = `${total.toFixed(2)}`;
                }
            });
        }

        // Add new expense
        function addExpense() {
            const amountInput = document.getElementById('amount');
            const categorySelect = document.getElementById('category');
            const dateInput = document.getElementById('date');

            const amount = parseFloat(amountInput.value);
            const category = categorySelect.value;
            const date = dateInput.value;

            if (isNaN(amount) || amount <= 0) {
                showError("Invalid amount. Please enter a positive number.");
                return;
            }

            // Validate date range
            const startDate = new Date(date);
            const endDate = new Date();
            endDate.setDate(endDate.getDate() + 1); // exclusive

            if (startDate > endDate) {
                showError("Start date cannot be after end date.");
                return;
            }

            // Create expense object
            const expense = {
                id: Date.now(), // unique ID
                amount,
                category,
                date: new Date(date),
                note: document.getElementById('note').value || ''
            };

            expenses.push(expense);
            renderExpenses();
            updateTotal();
            updateCategoryTotals();
        }

        // Show error message
        function showError(message) {
            const formError = document.querySelector('.form-error');
            if (formError) {
                formError.textContent = message;
            }
        }

        // Validate category selection
        function validateCategory() {
            const selected = categorySelect.value;
            if (!selected) {
                showError("Please select a category.");
                return false;
            }

            // Check if selected category exists in data (for persistence)
            const storedExpenses = JSON.parse(localStorage.getItem('expenseTrackerExpenses')) || [];
            const index = storedExpenses.findIndex(exp => exp.category === selected);
            if (index !== -1) {
                showError("Category already selected.");
                return false;
            }
        }

        // Validate form submission
        function validateForm() {
            const amountInput = document.getElementById('amount');
            const categorySelect = document.getElementById('category');
            const dateInput = document.getElementById('date');

            let isValid = true;

            // Validate amount
            if (isNaN(parseFloat(amountInput.value)) || parseFloat(amountInput.value) <= 0) {
                showError("Invalid amount. Please enter a positive number.");
                isValid = false;
            }

            // Validate category selection
            if (!validateCategory()) {
                isValid = false;
            }

            // Validate date range (if both date inputs are present)
            if (dateInput.value && startDate) {
                const startDateObj = new Date(startDate);
                const endDateObj = new Date(endDate.value);

                if (startDateObj > endDateObj) {
                    showError("Start date cannot be after end date.");
                    isValid = false;
                }
            }

            return isValid;
        }

        // Update filters
        function updateFilters() {
            const filterCategorySelect = document.getElementById('filter-category');
            const startDateInput = document.getElementById('start-date');
            const endDateInput = document.getElementById('end-date');

            // Clear previous selections
            filterCategorySelect.innerHTML = '<option value="all">All Categories</option>';
            for (let i = 0; i < categories.length; i++) {
                filterCategorySelect.innerHTML += `<option value="${i}">${categories[i]}</option>`;
            }

            // Update start date
            if (startDateInput) {
                const startDateObj = new Date(startDateInput.value);
                const validCategories = expenses.filter(expense => expense.date && expense.date >= startDateObj);

                for (let i = 0; i < validCategories.length; i++) {
                    filterCategorySelect.innerHTML += `<option value="${i}">${validCategories[i]}</option>`;
                }
            }

            // Update end date
            if (endDateInput) {
                const endDateObj = new Date(endDateInput.value);
                const validCategories = expenses.filter(expense => expense.date && expense.date <= endDateObj);

                for (let i = 0; i < validCategories.length; i++) {
                    filterCategorySelect.innerHTML += `<option value="${i}">${validCategories[i]}</option>`;
                }
            }
        }

        // Event listeners
        document.getElementById('add-expense-btn').addEventListener('click', addExpense);
        categorySelect.addEventListener('change', validateCategory);
        dateInput.addEventListener('change', updateFilters);
        startDateInput.addEventListener('change', updateFilters);
        endDateInput.addEventListener('change', updateFilters);

        // Delete button event (for delete buttons)
        document.querySelectorAll('.delete-btn').forEach(btn => {
            btn.addEventListener('click', function() {
                const expenseId = this.getAttribute('data-expense-id');
                if (expenseId) {
                    expenses = expenses.filter(expense => expense.id !== expenseId);
                    renderExpenses();
                    updateTotal();
                    updateCategoryTotals();
                }
            });
        });

        // Initialize on load
        window.addEventListener('DOMContentLoaded', () => {
            initializeExpenses(storedExpenses || []);
        });
    </script>
</body>
</html>
